import{M as e,_ as t,d as n,g as r,h as i,q as a,z as o}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as s}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var c=JSON.parse(`{"title":"Env Variables and Modes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/env-and-mode.md","filePath":"guide/env-and-mode.md"}`),l={name:`guide/env-and-mode.md`};function u(s,c,l,u,d,f){let p=o(`ScrimbaLink`);return e(),n(`div`,null,[c[1]||=i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\env-and-mode.md for this page in Markdown format</div><h1 id="env-variables-and-modes" tabindex="-1">Env Variables and Modes <a class="header-anchor" href="#env-variables-and-modes" aria-label="Permalink to “Env Variables and Modes”">​</a></h1><p>Vite exposes certain constants under the special <code>import.meta.env</code> object. These constants are defined as global variables during dev and statically replaced at build time to make tree-shaking effective.</p><details class="details custom-block"><summary>Example</summary><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.env.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DEV</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // code inside here will be tree-shaken in production builds</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Dev mode&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></details>`,4),t(p,{href:`https://scrimba.com/intro-to-vite-c03p6pbbdq/~05an?via=vite`,title:`Env Variables in Vite`},{default:a(()=>[...c[0]||=[r(`Watch an interactive lesson on Scrimba`,-1)]]),_:1}),c[2]||=i(`<h2 id="built-in-constants" tabindex="-1">Built-in Constants <a class="header-anchor" href="#built-in-constants" aria-label="Permalink to “Built-in Constants”">​</a></h2><p>Some built-in constants are available in all cases:</p><ul><li><p><strong><code>import.meta.env.MODE</code></strong>: {string} the <a href="#modes">mode</a> the app is running in.</p></li><li><p><strong><code>import.meta.env.BASE_URL</code></strong>: {string} the base url the app is being served from. This is determined by the <a href="/config/shared-options#base"><code>base</code> config option</a>.</p></li><li><p><strong><code>import.meta.env.PROD</code></strong>: {boolean} whether the app is running in production (running the dev server with <code>NODE_ENV=&#39;production&#39;</code> or running an app built with <code>NODE_ENV=&#39;production&#39;</code>).</p></li><li><p><strong><code>import.meta.env.DEV</code></strong>: {boolean} whether the app is running in development (always the opposite of <code>import.meta.env.PROD</code>)</p></li><li><p><strong><code>import.meta.env.SSR</code></strong>: {boolean} whether the app is running in the <a href="./ssr#conditional-logic">server</a>.</p></li></ul><h2 id="env-variables" tabindex="-1">Env Variables <a class="header-anchor" href="#env-variables" aria-label="Permalink to “Env Variables”">​</a></h2><p>Vite exposes env variables under the <code>import.meta.env</code> object as strings automatically.</p><p>Variables prefixed with <code>VITE_</code> will be exposed in client-side source code after Vite bundling. To prevent accidentally leaking env variables to the client, avoid using this prefix. As an example, consider the following:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env">.env</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>VITE_SOME_KEY=123</span></span>
<span class="line"><span>DB_PASSWORD=foobar</span></span></code></pre></div></div><p>The parsed value of <code>VITE_SOME_KEY</code> – <code>&quot;123&quot;</code> – will be exposed on the client, but the value of <code>DB_PASSWORD</code> will not. You can test this by adding the following to your code:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.env.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">VITE_SOME_KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;123&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.env.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DB_PASSWORD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// undefined</span></span></code></pre></div><p>If you want to customize the env variables prefix, see the <a href="/config/shared-options.html#envprefix">envPrefix</a> option.</p><div class="tip custom-block"><p class="custom-block-title">Env parsing</p><p>As shown above, <code>VITE_SOME_KEY</code> is a number but returns a string when parsed. The same would also happen for boolean env variables. Make sure to convert to the desired type when using it in your code.</p></div><div class="warning custom-block"><p class="custom-block-title">Protecting secrets</p><p><code>VITE_*</code> variables should <em>not</em> contain sensitive information such as API keys. The values of these variables are bundled into your source code at build time. For production deployments, consider a backend server or serverless/edge functions to properly secure secrets.</p></div><h3 id="env-files" tabindex="-1"><code>.env</code> Files <a class="header-anchor" href="#env-files" aria-label="Permalink to “.env Files”">​</a></h3><p>Vite uses <a href="https://github.com/motdotla/dotenv" target="_blank" rel="noreferrer">dotenv</a> to load additional environment variables from the following files in your <a href="/config/shared-options#envdir">environment directory</a>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>.env                # loaded in all cases</span></span>
<span class="line"><span>.env.local          # loaded in all cases, ignored by git</span></span>
<span class="line"><span>.env.[mode]         # only loaded in specified mode</span></span>
<span class="line"><span>.env.[mode].local   # only loaded in specified mode, ignored by git</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Env Loading Priorities</p><p>An env file for a specific mode (e.g. <code>.env.production</code>) will take higher priority than a generic one (e.g. <code>.env</code>).</p><p>Vite will always load <code>.env</code> and <code>.env.local</code> in addition to the mode-specific <code>.env.[mode]</code> file. Variables declared in mode-specific files will take precedence over those in generic files, but variables defined only in <code>.env</code> or <code>.env.local</code> will still be available in the environment.</p><p>In addition, environment variables that already exist when Vite is executed have the highest priority and will not be overwritten by <code>.env</code> files. For example, when running <code>VITE_SOME_KEY=123 vite build</code>.</p><p><code>.env</code> files are loaded at the start of Vite. Restart the server after making changes.</p></div><div class="warning custom-block"><p class="custom-block-title">Bun users</p><p>When using <a href="https://bun.sh" target="_blank" rel="noreferrer">Bun</a>, be aware that Bun automatically loads <code>.env</code> files before your script runs. This built-in behavior loads environment variables directly into <code>process.env</code> and can interfere with Vite&#39;s feature, as it respects existing <code>process.env</code> values. See <a href="https://github.com/oven-sh/bun/issues/5515" target="_blank" rel="noreferrer">oven-sh/bun#5515</a> for workarounds.</p></div><p>Also, Vite uses <a href="https://github.com/motdotla/dotenv-expand" target="_blank" rel="noreferrer">dotenv-expand</a> to expand variables written in env files out of the box. To learn more about the syntax, check out <a href="https://github.com/motdotla/dotenv-expand#what-rules-does-the-expansion-engine-follow" target="_blank" rel="noreferrer">their docs</a>.</p><p>Note that if you want to use <code>$</code> inside your environment value, you have to escape it with <code>\\</code>.</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env">.env</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>KEY=123</span></span>
<span class="line"><span>NEW_KEY1=test$foo   # test</span></span>
<span class="line"><span>NEW_KEY2=test\\$foo  # test$foo</span></span>
<span class="line"><span>NEW_KEY3=test$KEY   # test123</span></span></code></pre></div></div><details class="details custom-block"><summary>Expanding variables in reverse order</summary><p>Vite supports expanding variables in reverse order. For example, the <code>.env</code> below will be evaluated as <code>VITE_FOO=foobar</code>, <code>VITE_BAR=bar</code>.</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env">.env</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>VITE_FOO=foo\${VITE_BAR}</span></span>
<span class="line"><span>VITE_BAR=bar</span></span></code></pre></div></div><p>This does not work in shell scripts and other tools like <code>docker compose</code>. That said, Vite supports this behavior as this has been supported by <code>dotenv-expand</code> for a long time and other tools in JavaScript ecosystem use older versions that support this behavior.</p><p>To avoid interop issues, it is recommended to avoid relying on this behavior. Vite may start emitting warnings for this behavior in the future.</p></details><div class="warning custom-block"><p class="custom-block-title">Ignoring local <code>.env</code> files</p><p><code>.env.*.local</code> files are local-only and can contain sensitive variables. You should add <code>*.local</code> to your <code>.gitignore</code> to avoid them being checked into git.</p></div><h2 id="intellisense-for-typescript" tabindex="-1">IntelliSense for TypeScript <a class="header-anchor" href="#intellisense-for-typescript" aria-label="Permalink to “IntelliSense for TypeScript”">​</a></h2><p>By default, Vite provides type definitions for <code>import.meta.env</code> in <a href="https://github.com/vitejs/vite/blob/main/packages/vite/client.d.ts" target="_blank" rel="noreferrer"><code>vite/client.d.ts</code></a>. While you can define more custom env variables in <code>.env.[mode]</code> files, you may want to get TypeScript IntelliSense for user-defined env variables that are prefixed with <code>VITE_</code>.</p><p>To achieve this, you can create an <code>vite-env.d.ts</code> in <code>src</code> directory, then augment <code>ImportMetaEnv</code> like this:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="vite-env.d.ts">vite-env.d.ts</span></div><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ViteTypeOptions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // By adding this line, you can make the type of ImportMetaEnv strict</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // to disallow unknown keys.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // strictImportMetaEnv: unknown</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ImportMetaEnv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  readonly</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> VITE_APP_TITLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // more env variables...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ImportMeta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  readonly</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> env</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ImportMetaEnv</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></div><p>If your code relies on types from browser environments such as <a href="https://github.com/microsoft/TypeScript/blob/main/src/lib/dom.generated.d.ts" target="_blank" rel="noreferrer">DOM</a> and <a href="https://github.com/microsoft/TypeScript/blob/main/src/lib/webworker.generated.d.ts" target="_blank" rel="noreferrer">WebWorker</a>, you can update the <a href="https://www.typescriptlang.org/tsconfig#lib" target="_blank" rel="noreferrer">lib</a> field in <code>tsconfig.json</code>.</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="tsconfig.json">tsconfig.json</span></div><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;lib&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WebWorker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">Imports will break type augmentation</p><p>If the <code>ImportMetaEnv</code> augmentation does not work, make sure you do not have any <code>import</code> statements in <code>vite-env.d.ts</code>. See the <a href="https://www.typescriptlang.org/docs/handbook/2/modules.html#how-javascript-modules-are-defined" target="_blank" rel="noreferrer">TypeScript documentation</a> for more information.</p></div><h2 id="html-constant-replacement" tabindex="-1">HTML Constant Replacement <a class="header-anchor" href="#html-constant-replacement" aria-label="Permalink to “HTML Constant Replacement”">​</a></h2><p>Vite also supports replacing constants in HTML files. Any properties in <code>import.meta.env</code> can be used in HTML files with a special <code>%CONST_NAME%</code> syntax:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Vite is running in %MODE%&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Using data from %VITE_API_URL%&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>If the env doesn&#39;t exist in <code>import.meta.env</code>, e.g. <code>%NON_EXISTENT%</code>, it will be ignored and not replaced, unlike <code>import.meta.env.NON_EXISTENT</code> in JS where it&#39;s replaced as <code>undefined</code>.</p><p>Given that Vite is used by many frameworks, it is intentionally unopinionated about complex replacements like conditionals. Vite can be extended using <a href="https://github.com/vitejs/awesome-vite#transformers" target="_blank" rel="noreferrer">an existing userland plugin</a> or a custom plugin that implements the <a href="./api-plugin#transformindexhtml"><code>transformIndexHtml</code> hook</a>.</p><h2 id="modes" tabindex="-1">Modes <a class="header-anchor" href="#modes" aria-label="Permalink to “Modes”">​</a></h2><p>By default, the dev server (<code>dev</code> command) runs in <code>development</code> mode and the <code>build</code> command runs in <code>production</code> mode.</p><p>This means when running <code>vite build</code>, it will load the env variables from <code>.env.production</code> if there is one:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env.production">.env.production</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>VITE_APP_TITLE=My App</span></span></code></pre></div></div><p>In your app, you can render the title using <code>import.meta.env.VITE_APP_TITLE</code>.</p><p>In some cases, you may want to run <code>vite build</code> with a different mode to render a different title. You can overwrite the default mode used for a command by passing the <code>--mode</code> option flag. For example, if you want to build your app for a staging mode:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vite</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> staging</span></span></code></pre></div><p>And create a <code>.env.staging</code> file:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env.staging">.env.staging</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>VITE_APP_TITLE=My App (staging)</span></span></code></pre></div></div><p>As <code>vite build</code> runs a production build by default, you can also change this and run a development build by using a different mode and <code>.env</code> file configuration:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title=".env.testing">.env.testing</span></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>NODE_ENV=development</span></span></code></pre></div></div><h3 id="node-env-and-modes" tabindex="-1">NODE_ENV and Modes <a class="header-anchor" href="#node-env-and-modes" aria-label="Permalink to “NODE_ENV and Modes”">​</a></h3><p>It&#39;s important to note that <code>NODE_ENV</code> (<code>process.env.NODE_ENV</code>) and modes are two different concepts. Here&#39;s how different commands affect the <code>NODE_ENV</code> and mode:</p><table tabindex="0"><thead><tr><th>Command</th><th>NODE_ENV</th><th>Mode</th></tr></thead><tbody><tr><td><code>vite build</code></td><td><code>&quot;production&quot;</code></td><td><code>&quot;production&quot;</code></td></tr><tr><td><code>vite build --mode development</code></td><td><code>&quot;production&quot;</code></td><td><code>&quot;development&quot;</code></td></tr><tr><td><code>NODE_ENV=development vite build</code></td><td><code>&quot;development&quot;</code></td><td><code>&quot;production&quot;</code></td></tr><tr><td><code>NODE_ENV=development vite build --mode development</code></td><td><code>&quot;development&quot;</code></td><td><code>&quot;development&quot;</code></td></tr></tbody></table><p>The different values of <code>NODE_ENV</code> and mode also reflect on its corresponding <code>import.meta.env</code> properties:</p><table tabindex="0"><thead><tr><th>Command</th><th><code>import.meta.env.PROD</code></th><th><code>import.meta.env.DEV</code></th></tr></thead><tbody><tr><td><code>NODE_ENV=production</code></td><td><code>true</code></td><td><code>false</code></td></tr><tr><td><code>NODE_ENV=development</code></td><td><code>false</code></td><td><code>true</code></td></tr><tr><td><code>NODE_ENV=other</code></td><td><code>false</code></td><td><code>true</code></td></tr></tbody></table><table tabindex="0"><thead><tr><th>Command</th><th><code>import.meta.env.MODE</code></th></tr></thead><tbody><tr><td><code>--mode production</code></td><td><code>&quot;production&quot;</code></td></tr><tr><td><code>--mode development</code></td><td><code>&quot;development&quot;</code></td></tr><tr><td><code>--mode staging</code></td><td><code>&quot;staging&quot;</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title"><code>NODE_ENV</code> in <code>.env</code> files</p><p><code>NODE_ENV=...</code> can be set in the command, and also in your <code>.env</code> file. If <code>NODE_ENV</code> is specified in a <code>.env.[mode]</code> file, the mode can be used to control its value. However, both <code>NODE_ENV</code> and modes remain as two different concepts.</p><p>The main benefit with <code>NODE_ENV=...</code> in the command is that it allows Vite to detect the value early. It also allows you to read <code>process.env.NODE_ENV</code> in your Vite config as Vite can only load the env files once the config is evaluated.</p></div>`,52)])}var d=s(l,[[`render`,u]]);export{c as __pageData,d as default};